export default function Perfil() {
  return (
    <div className="bg-verde h-44 shadow-xl w-full flex jus">
      <div className="w-96 bg-branco h-fit rounded-2xl">
        <img src="ft-perfil.svg" alt="Foto de perfil" />
        <h1 className="text-preto font-bold text-3xl text-center self-center">
          João Pedro
        </h1>
        <div className="h-[1px] bg-rodape w-full"></div>
        <h1 className="text-verde font-bold text-2xl text-center self-center">
          Posição no Ranking: 3
        </h1>
      </div>
    </div>
  );
}
